      }
    }

    assert r - keep >= 0;
    GreedyKeepSumBound(x[1..], r - keep);

    var tail := GreedyKeep(x[1..], r - keep);
    assert |gk| > 0;
    SumCons(gk);
    assert gk[0] == keep;
    assert gk[1..] == tail;
    assert keep <= x[0];
  }
